import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import productService from '../services/productService';
import categoryService from '../services/categoryService';
import { useAuth } from '../context/AuthContext';
import supportService from '../services/supportService';
import type { User } from '../types';

let homeCache = null;

const getHomeConcernsCacheKey = (userId) => `customer_home_concerns_cache_v1_${userId || 'guest'}`;

const readCachedConcerns = (userId) => {
    try {
        const raw = localStorage.getItem(getHomeConcernsCacheKey(userId));
        if (!raw) {
            return [];
        }

        const parsed = JSON.parse(raw);
        return Array.isArray(parsed) ? parsed : [];
    } catch {
        return [];
    }
};

export default function Home() {
    const { user } = useAuth() as { user: User | null };
    const welcomeName = user?.name?.trim() || (user as any)?.customer_info?.name?.trim() || user?.email?.split('@')[0] || 'Customer';
    const [featuredProducts, setFeaturedProducts] = useState(() => homeCache?.featuredProducts || []);
    const [categories, setCategories] = useState(() => homeCache?.categories || []);
    const [concerns, setConcerns] = useState(() => readCachedConcerns(user?.id));
    const [error, setError] = useState(null);

    useEffect(() => {
        const fetchData = async () => {
            if (homeCache) {
                setFeaturedProducts(homeCache.featuredProducts);
                setCategories(homeCache.categories);
                return;
            }

            try {
                const [productRes, categoryRes] = await Promise.all([
                    productService.getFeatured(),
                    categoryService.getAll(),
                ]);
                const nextFeatured = productRes.data.data;
                const nextCategories = categoryRes.data.data;

                setFeaturedProducts(nextFeatured);
                setCategories(nextCategories);
                homeCache = {
                    featuredProducts: nextFeatured,
                    categories: nextCategories,
                };
            } catch (err) {
                setError(err.message || 'Failed to load home data.');
            }
        };

        fetchData();
    }, []);

    useEffect(() => {
        const loadConcerns = async () => {
            if (!user) {
                setConcerns([]);
                return;
            }

            try {
                const res = await supportService.getMyConcerns({ limit: 3 });
                const nextConcerns = res?.data?.data?.data || res?.data?.data || [];
                setConcerns(nextConcerns.slice(0, 3));
                localStorage.setItem(getHomeConcernsCacheKey(user?.id), JSON.stringify(nextConcerns.slice(0, 3)));
            } catch {
                setConcerns(readCachedConcerns(user?.id));
            }
        };

        loadConcerns();
    }, [user]);

    return (
        <div className="home-page">
            {error && (
                <div className="empty-state">{error}</div>
            )}

            {user && (
                <section className="customer-dashboard">
                    <div className="customer-dashboard__inner">
                        <div className="customer-dashboard__intro">
                            <p className="customer-dashboard__kicker">Customer Dashboard</p>
                            <h2>Welcome back, {welcomeName}!</h2>
                            <p>Track your orders, update your profile, and continue shopping from one place.</p>
                        </div>

                        <div className="customer-dashboard__cards">
                            <Link to="/profile" className="dashboard-card">
                                <h3>My Profile</h3>
                                <p>Update your personal details and address.</p>
                            </Link>
                            <Link to="/orders" className="dashboard-card">
                                <h3>My Orders</h3>
                                <p>Check status and view your latest purchases.</p>
                            </Link>
                            <Link to="/products" className="dashboard-card">
                                <h3>Shop Products</h3>
                                <p>Explore parts and add items to your cart.</p>
                            </Link>
                            <Link to="/dashboard/cart" className="dashboard-card">
                                <h3>My Cart</h3>
                                <p>Review cart items and proceed to checkout.</p>
                            </Link>
                            <Link to="/profile" className="dashboard-card dashboard-card--concerns">
                                <h3>My Concerns</h3>
                                <p>
                                    {concerns.length > 0
                                        ? `${concerns.length} recent concern${concerns.length > 1 ? 's' : ''} waiting for updates.`
                                        : 'No concerns submitted yet. Use your profile to manage support issues.'}
                                </p>
                            </Link>
                        </div>

                        <div className="customer-dashboard__concerns">
                            <div className="customer-dashboard__concerns-head">
                                <div>
                                    <p className="customer-dashboard__kicker">Customer Concerns</p>
                                    <h3>Latest tickets</h3>
                                </div>
                                <Link to="/customer-service#support-form" className="btn btn-outline-primary btn-sm">Send Concern</Link>
                            </div>

                            {concerns.length > 0 ? (
                                <div className="customer-dashboard__concern-list">
                                    {concerns.map((concern) => (
                                        <article key={concern.id} className="customer-dashboard__concern-item">
                                            <div>
                                                <strong>{concern.subject}</strong>
                                                <p>{concern.message}</p>
                                            </div>
                                            <span className={`customer-dashboard__concern-status customer-dashboard__concern-status--${concern.status || 'pending'}`}>
                                                {concern.status || 'pending'}
                                            </span>
                                        </article>
                                    ))}
                                </div>
                            ) : (
                                <p className="customer-dashboard__concerns-empty">Your submitted concerns will appear here after login.</p>
                            )}
                        </div>
                    </div>
                </section>
            )}

            {/* Trust Indicators */}
            <section className="trust-section">
                <div className="trust-inner">
                    <div className="trust-logos">
                        <div className="trust-item">
                            <div className="trust-icon">
                                <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                                    <path d="M12 2l3.09 6.26L22 9.27l-5 4.87 1.18 6.88L12 17.77l-6.18 3.25L7 14.14 2 9.27l6.91-1.01L12 2z"/>
                                </svg>
                            </div>
                            <span>Genuine OEM Parts</span>
                        </div>
                        <div className="trust-item">
                            <div className="trust-icon">
                                <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                                    <rect x="1" y="3" width="15" height="13"/>
                                    <polygon points="16,8 20,8 23,12 16,12"/>
                                    <circle cx="5.5" cy="18.5" r="2.5"/>
                                    <circle cx="18.5" cy="18.5" r="2.5"/>
                                </svg>
                            </div>
                            <span>Free Shipping</span>
                        </div>
                        <div className="trust-item">
                            <div className="trust-icon">
                                <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                                    <path d="M3 12a9 9 0 0 1 9-9 9.75 9.75 0 0 1 6.74 2.74L21 8"/>
                                    <path d="M21 3v5h-5"/>
                                    <path d="M21 12a9 9 0 0 1-9 9 9.75 9.75 0 0 1-6.74-2.74L3 16"/>
                                    <path d="M8 16H3v5"/>
                                </svg>
                            </div>
                            <span>30-Day Returns</span>
                        </div>
                        <div className="trust-item">
                            <div className="trust-icon">
                                <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                                    <path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/>
                                    <polyline points="14,2 14,8 20,8"/>
                                    <line x1="16" y1="13" x2="8" y2="13"/>
                                    <line x1="16" y1="17" x2="8" y2="17"/>
                                    <polyline points="10,9 9,9 8,9"/>
                                </svg>
                            </div>
                            <span>Expert Support</span>
                        </div>
                    </div>
                </div>
            </section>

            {/* Categories Section */}
            <section className="categories-section">
                <div className="section-container">
                    <div className="section-header">
                        <h2 className="section-title">Shop by Category</h2>
                        <p className="section-subtitle">
                            Find the perfect parts for your vehicle across our comprehensive categories
                        </p>
                    </div>
                    <div className="categories-grid">
                        {categories.map((category) => (
                            <Link
                                key={category.id}
                                to={`/products?category=${category.id}`}
                                className="category-card"
                            >
                                <div className="category-icon">
                                    <div className="icon-wrapper">
                                        <span className="icon-placeholder"></span>
                                    </div>
                                </div>
                                <div className="category-content">
                                    <h3 className="category-title">{category.name}</h3>
                                    <p className="category-count">{category.products_count} products</p>
                                    <div className="category-arrow">
                                        <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                                            <path d="M5 12h14M12 5l7 7-7 7"/>
                                        </svg>
                                    </div>
                                </div>
                            </Link>
                        ))}
                    </div>
                </div>
            </section>

            {/* Featured Products Section */}
            <section className="featured-section">
                <div className="section-container">
                    <div className="section-header">
                        <h2 className="section-title">Featured Products</h2>
                        <p className="section-subtitle">
                            Handpicked premium parts trusted by professionals and enthusiasts
                        </p>
                    </div>
                    <div className="products-grid">
                        {featuredProducts.map((product) => (
                            <Link
                                key={product.id}
                                to={`/products/${product.id}`}
                                className="product-card"
                            >
                                <div className="product-image">
                                    {product.images?.[0] ? (
                                        <img
                                            src={product.images[0]}
                                            alt={product.name}
                                            loading="lazy"
                                        />
                                    ) : (
                                        <div className="product-placeholder">
                                            <svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1">
                                                <rect x="3" y="3" width="18" height="18" rx="2" ry="2"/>
                                                <circle cx="9" cy="9" r="2"/>
                                                <path d="m21 15-3.086-3.086a2 2 0 0 0-2.828 0L6 21"/>
                                            </svg>
                                        </div>
                                    )}
                                    {product.stock < 5 && product.stock > 0 && (
                                        <div className="product-badge low-stock">Low Stock</div>
                                    )}
                                    {product.stock === 0 && (
                                        <div className="product-badge out-of-stock">Out of Stock</div>
                                    )}
                                </div>
                                <div className="product-content">
                                    <div className="product-brand">{product.brand}</div>
                                    <h3 className="product-title">{product.name}</h3>
                                    <div className="product-price">
                                        <span className="price-amount">₱{product.price}</span>
                                    </div>
                                    <div className="product-meta">
                                        <span className={`stock-status ${product.stock > 0 ? 'in-stock' : 'out-of-stock'}`}>
                                            {product.stock > 0 ? `${product.stock} in stock` : 'Out of stock'}
                                        </span>
                                    </div>
                                </div>
                            </Link>
                        ))}
                    </div>
                    <div className="section-footer">
                        <Link to="/products" className="btn btn-outline-primary">
                            <span>View All Products</span>
                            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                                <path d="M5 12h14M12 5l7 7-7 7"/>
                            </svg>
                        </Link>
                    </div>
                </div>
            </section>
        </div>
    );
}
